create or replace function snowconvert.public.collate_ltrim_udf(A string, B string, C string)
  returns string
  language javascript
  as
  $$  
      var exit = 0;
      var new_str_len = A.length;
      var match_len = B.length;
      var new_str = A;
      if (C == 'N')
        {var match_str = B.toUpperCase();}
      else {var match_str = B.value;};    

       do
        {
        var test_str = new_str.substring(0,match_len);

        if (C == 'N')
            {test_str = test_str.toUpperCase();};

        if (test_str === match_str) 
           {
            new_str = new_str.substr(match_len);
            new_str_len = new_str.length;
            exit = 0;
            }
        else
            {
            exit = 1;
            }; 
        }
    while (exit == 0); 

    return new_str;
  $$;

