Here is a javascript UDTF we can leverage to start.  We can't dynamically control the column names returned, so the converter will need to substitute in for the originals based upon the column names defined.  Also, it doesn't yet handle all the option flags 

i = works
c = should be ignored
m = accepts, not tested
n = let's flag as a review if found and ignore
l = let's flag as a review if found and ignore


CREATE OR REPLACE FUNCTION UDF_REGEXP_SPLIT_TO_TABLE(
    INPUT_KEY       VARCHAR,
    SOURCE_STRING   VARCHAR,
    REXPRESS        VARCHAR,
    OPTIONS         VARCHAR
    ) 
    RETURNS TABLE(
      __OUTPUT_KEY__    VARCHAR,
      __TOKENNUM__      DOUBLE,
      __TOKEN__         VARCHAR
    )
    LANGUAGE JAVASCRIPT 
AS $${
    processRow: function f(row, rowWriter, context) {  
        var patt = new RegExp(row.REXPRESS, row.OPTIONS);
        var source_array = row.SOURCE_STRING.split(patt);
        for (i = 0; i < source_array.length; i++) {
            rowWriter.writeRow({"__OUTPUT_KEY__":row.INPUT_KEY, "__TOKENNUM__": 1+i, "__TOKEN__": source_array[i]});
        }  
    }
}$$
;

